-- Get Mega Electrics services
SELECT externalId, serviceType, serviceTypeDetail, planName, supplierName, customerName, 
       monthlyCost, monthlyRevenue, technology, speedTier, connectionId, locationAddress, billingPlatform
FROM services WHERE customerExternalId = 'C0159' ORDER BY serviceType, supplierName;

-- Check billing_items structure
DESCRIBE billing_items;

